html:
{% set attendees = frappe.get_all(
    'Event Attendee',
    fields = ['name1', 'company_name', 'category', 'qr', 'name'],
    filters = {
        'name1': ['in', [
            'Gourav Mehta',
            'Ketan Maheshwari',
            'Mahaveer P Jain Gadiya',
            'Mahendra Kochar',
            'Motilal Balar',
            'Nisarg Shah',
            'Pankaj Jain',
            'Pankaj Kataria',
            'Pathikk Shah',
            'Peeyush Shah',
            'Praful Mutha',
            'Pragati Pugaliya',
            'Prasanth SA',
            'Pritesh Gadiya',
            'Rajesh Bhosagi',
            'Rakesh Barmecha',
            'Reshma Doshi',
            'Sachin Doshi',
            'Shreyansh Vaidya',
            'Shruti Bora',
            'Trishla Shah',
            'Vijaykumar Mehta',
            'Ashwin Jain',
            'Asheesh Jain',
            'Ashish Lunkar Jain',
            'Apurva Dakaliya',
            'Archana Sand',
            'Anupreksha Jain',
            'Akshay R Bagrecha'
        ]]
        }
        )
        %}
<style>
	@page {
		size: 12in 18in;
		margin: 0.20in;
	}

	html, body {
		margin: 0;
		padding: 0;
		font-family: Arial, Helvetica, sans-serif;
		color: #111;
		font-size: 8pt;
	}

	.sheet {
		width: 100%;
	}

	/* 3 cards per row on 12in page */
	.badge-grid {
		display: grid;
		grid-template-columns: repeat(3, 114mm);
		grid-auto-rows: 76mm;
		gap: 3mm;
		justify-content: start;
		align-content: start;
	}

	/* ── CARD ── */
	.badge {
		width: 114mm;
		height: 76mm;
		box-sizing: border-box;
		border: 1px solid #cfcfcf;
		padding: 2.5mm;
		display: flex;
		flex-direction: column;
		page-break-inside: avoid;
		break-inside: avoid;
		overflow: hidden;
		background: #fff;
	}

	/* ── TOP ROW: QR side | Info side ── */
	.top-row {
		display: flex;
		flex-direction: row;
		align-items: flex-start;
		flex: 1;
		min-height: 0;
		gap: 2.5mm;
	}

	/* LEFT: badge-id + QR */
	.left {
		display: flex;
		flex-direction: column;
		align-items: center;
		width: 32mm;
		flex-shrink: 0;
	}

	.badge-id {
		font-size: 7px;
		font-weight: 700;
		color: #333;
		text-align: center;
		margin-bottom: 1mm;
		letter-spacing: 0.3px;
	}

	.qr-box {
		width: 30mm;
		height: 30mm;
		border: 1px solid #ddd;
		display: flex;
		align-items: center;
		justify-content: center;
		background: #fff;
		overflow: hidden;
	}

	.qr-box img {
		width: 94%;
		height: 94%;
		object-fit: contain;
		display: block;
	}

	.no-qr {
		font-size: 6pt;
		color: #777;
		text-align: center;
		line-height: 1.2;
		padding: 2px;
	}

	/* RIGHT: name + company + table */
	.right {
		flex: 1;
		display: flex;
		flex-direction: column;
		text-align:left;
		min-width: 0;
		margin-top:18px;
	}

	.attendee-name {
		font-size: 15px;
		font-weight: 700;
		line-height: 1.2;
		margin-bottom: 1.5mm;
		overflow-wrap: break-word;
		word-break: break-word;
	}

	.company-name {
		font-size: 16px;
		font-weight: 700;
		line-height: 1.2;
		overflow-wrap: break-word;
		word-break: break-word;
		margin-bottom: 1.5mm;
	}

	/* ── BOTTOM ROW: BYOB | SWOT equal width ── */
	.bottom-row {
		display: flex;
		flex-direction: row;
		align-items: stretch;
		gap: 2.5mm;           /* centered gap between the two boxes */
		margin-top: 2mm;
		flex-shrink: 0;
	}

	.bottom-col {
		flex: 1;              /* both cols take exactly equal width */
		display: flex;
		flex-direction: column;
		gap: 1mm;
	}

	.bottom-label {
		font-size: 7.5px;
		font-weight: 700;
		line-height: 1.2;
	}

	.write-box {
		flex: 1;
		min-height: 10mm;
		border: 1px solid #bfbfbf;
		box-sizing: border-box;
		padding: 1px 2px;
		font-size: 7px;
		line-height: 1.2;
		background: #fff;
	}

	/* Table numbers row — sits below BYOB/SWOT */
	.table-row {
		display: flex;
		flex-direction: row;
		justify-content: space-between;
		margin-top: 1.5mm;
		flex-shrink: 0;
	}

	.table-no {
		font-size: 7px;
		text-align:center;
	}

	.empty-state {
		padding: 24px;
		font-size: 12pt;
		color: #444;
	}
</style>

<div class="sheet">
	{% if attendees and attendees|length > 0 %}
		<div class="badge-grid">
			{% for row in attendees %}
				<div class="badge">

					<!-- TOP ROW -->
					<div class="top-row">

						<!-- Left: Badge ID + QR -->
						<div class="left">
							<div class="badge-id">{{ row.name }}</div>
							{% if row.qr %}
								<div class="qr-box">
									<img src="{{ row.qr }}" alt="{{ row.name1 }}">
								</div>
							{% else %}
								<div class="qr-box">
									<div class="no-qr">No QR</div>
								</div>
							{% endif %}
						</div>

						<!-- Right: Name + Company -->
						<div class="right">
							<div class="attendee-name">{{ row.name1 }}</div>
							<div class="company-name">{{  row.category }}</div>
							<div class="company-name">{{  row.company_name }}</div>
						</div>

					</div>

					<!-- BOTTOM ROW: BYOB | SWOT equal width, gap centered -->
					<div class="bottom-row">
						<div class="bottom-col">
							<div class="bottom-label">BYOB Detail</div>
							<div class="write-box">&nbsp;</div>
						</div>
						<div class="bottom-col">
							<div class="bottom-label">Put your SWOT</div>
							<div class="write-box">&nbsp;</div>
						</div>
					</div>

					<!-- TABLE NUMBERS: after BYOB & SWOT boxes -->


				</div>
			{% endfor %}
		</div>
	{% else %}
		<div class="empty-state">No Event Attendee records found.</div>
	{% endif %}
</div>
